public class Main {
    static class Node {
        int data;
        Node next;
        Node(int data) { this.data = data; }
    }

    public static void main(String[] args) {
        Node first = new Node(10);
        Node second = new Node(20);
        Node third = new Node(30);

        first.next = second;
        second.next = third;
        third.next = first; // loops back to the start -- no null anywhere

        System.out.println(third.next.data); // 10 -- following the loop back around
        System.out.println(third.next.next.data); // 20
    }
}

public class Main {
    static class Node {
        int data;
        Node next;
        Node(int data) { this.data = data; }
    }

    public static void main(String[] args) {
        Node first = new Node(10);
        Node second = new Node(20);
        Node third = new Node(30);

        first.next = second;
        second.next = third;
        third.next = first;

        Node current = first;
        do {
            System.out.print(current.data + " ");
            current = current.next;
        } while (current != first);
    }
}

public class Main {
    static class Node {
        int data;
        Node next;
        Node(int data) { this.data = data; }
    }

    static Node last; // keep a reference to the LAST node for convenience

    static void insertAtEnd(int data) {
        Node newNode = new Node(data);
        if (last == null) {
            last = newNode;
            newNode.next = newNode; // points to itself -- a circle of one
            return;
        }
        newNode.next = last.next; // new node points to the current first node
        last.next = newNode;      // old last points to the new node
        last = newNode;           // new node becomes the last node
    }

    static void printList() {
        if (last == null) return;
        Node first = last.next;
        Node current = first;
        do {
            System.out.print(current.data + " ");
            current = current.next;
        } while (current != first);
        System.out.println();
    }

    public static void main(String[] args) {
        insertAtEnd(10);
        insertAtEnd(20);
        insertAtEnd(30);
        printList();
    }
}

